SELECT c.doc_code, c.doc_name, c.parent, c.doc_sort, c.create_user, c.create_time, c.update_user, c.update_time, c.doc_type_sign, c.type_sign_start, c.type_sign_end, c.office_limit, c.img_limit, c.audio_limit, c.video_limit, c.other_limit, c.min_files, c.max_files, c.is_regularized, c.is_obscured, c.is_remade, c.is_plagiarism, c.is_auto_classified, c.auto_classification_id, c.is_parent FROM ecm_doc_def c WHERE NOT EXISTS( SELECT 1 FROM ecm_doc_def sub WHERE sub.parent = c.doc_code )
AND c.is_remade = #{isRemade}
AND c.is_regularized = #{isRegularized}
AND c.is_obscured = #{isObscured}
AND c.is_plagiarism = #{isPlagiarism}
AND c.is_auto_classified = #{isAutoClassified}

